// Input: city, state, route_number, zip_code, categories
const body = $input.first().json.body;
const city = body.city || 'Fayetteville';
const state = body.state || 'NC';
const routeNumber = body.route_number;
const zipCode = body.zip_code;
const categories = (body.categories || 'tattoo shop,barbershop,hair salon,gym,restaurant,bar,real estate,insurance,lawyer,dentist').split(',').map(s => s.trim());

if (!routeNumber || !zipCode) {
  throw new Error('route_number and zip_code are required');
}

// Generate search queries for each category in this zip code
const queries = categories.map(cat => `${cat} in ${zipCode}`);

return [{
  json: {
    city,
    state,
    route_number: routeNumber,
    zip_code: zipCode,
    queries,
    categories
  }
}];

// Create a query for each category
const input = $input.first().json;
return input.queries.map(q => ({
  json: {
    query: q,
    city: input.city,
    state: input.state,
    route_number: input.route_number,
    zip_code: input.zip_code
  }
}));

// Parse Google Places results and filter by zip code
const results = $input.all();
const prospects = [];
const routeInfo = results[0]?.json || {};

for (const item of results) {
  const places = item.json.results || [];

  for (const place of places) {
    if (!place.name) continue;

    // Extract zip from address
    const address = place.formatted_address || '';
    const zipMatch = address.match(/\b(\d{5})\b/);
    const zip = zipMatch ? zipMatch[1] : '';

    // Only include if in target zip code (or close match)
    if (zip && zip !== routeInfo.zip_code) {
      continue; // Skip businesses outside target zip
    }

    prospects.push({
      json: {
        business_name: place.name,
        address: address,
        phone: place.formatted_phone_number || '',
        website: place.website || '',
        google_rating: place.rating || null,
        review_count: place.user_ratings_total || 0,
        category: place.types ? place.types[0] : 'other',
        google_place_id: place.place_id,
        lat: place.geometry?.location?.lat,
        lng: place.geometry?.location?.lng,
        zip: zip,
        city: routeInfo.city,
        state: routeInfo.state,
        source: 'google_maps',
        route_number: routeInfo.route_number,
        zip_code: routeInfo.zip_code
      }
    });
  }
}

// Deduplicate by business_name + address
const seen = new Set();
const unique = prospects.filter(p => {
  const key = `${p.json.business_name}|${p.json.address}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

console.log(`Found ${unique.length} unique prospects in zip ${routeInfo.zip_code}`);
return unique;

// Attach route_id to each prospect
const routeId = $input.first().json[0]?.id;
const prospects = $('Parse & Filter by Zip').all();

if (!routeId) {
  throw new Error('Route not found in database');
}

return prospects.map(p => ({
  json: {
    ...p.json,
    route_id: routeId
  }
}));

const count = $input.all().length;
const routeInfo = $('Parse Input').first().json;
return [{ json: { success: true, prospects_added: count, route_number: routeInfo.route_number, zip_code: routeInfo.zip_code, message: `Scraped ${count} prospects for Route ${routeInfo.route_number} (${routeInfo.zip_code})` } }];
